def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        base = np.power(cap, 0.45) + np.log1p(item * 7)
        complexity = 0.0
        factor = 1.0
        shift = 1.0
        enhance = 1.0
        penalty = 0.0
        for x in range(1, 15):
            if x % 2 == 0:
                factor *= 1 + 0.02 * np.sin(x + item)
            else:
                factor *= 0.95 + 0.01 * (x % 3)
            ratio = item / (cap + 1e-6)
            if ratio < 0.3 * x:
                complexity += (x * np.cos(ratio * x) + np.tanh(item / (cap + x))) * factor
            else:
                complexity += (np.exp(-x / (item + 1)) + np.sqrt(ratio * x)) * factor / (x + 1)
            if (cap * x + item) % 11 == 0:
                complexity *= 1.07
            elif (cap + x * x) % 9 == 0:
                complexity *= 0.93
            if x == 7:
                for y in range(1, 7):
                    dist = abs(cap - item * (y**3))
                    if dist < 10:
                        penalty += np.exp(-dist) * 0.8 / (y + 1)
                    else:
                        penalty -= np.log1p(dist) / (y + 2)
            if ratio > 0.8 and x % 4 == 0:
                enhance *= 1.12 + 0.03 * x
            elif ratio < 0.15 and x % 5 == 0:
                enhance *= 0.88 - 0.02 * x
            if x % 6 == 1 and cap % (x + 2) == 0:
                penalty += np.cos(x * ratio) * 0.7
        score = complexity + penalty * 0.9
        score *= shift * enhance
        if score < 0:
            priorities[i] = -score * (np.sqrt(cap + item) + np.log1p(cap))
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.log1p(cap) + 1) * (1 + ratio**1.5)
            else:
                priorities[i] = -score / (cap + 2) * np.exp(-ratio**3)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.1:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.96
        elif cap % 5 == 0:
            priorities[i] *= 1.04
        for prime in [2,3,5,7]:
            if (cap + item) % prime == 0:
                priorities[i] *= 1 + 0.01 * prime
    return priorities
